INSERT INTO public.document_chunks VALUES (72, 5, 'd39aaabe0b177a98b5e04fdbe7aa32caa41462d7c5c789e4b9d5ec09ada03ba1', 'Is there a character limit for the Ad Group Name?', 'We follow Google''s limits behind the scenes. Practically speaking:
Keep Ad Group Names short and scannable, ideally under 80 characters.
Use plain text without emojis or special characters, which can make reporting harder to read.
If you hit a limit, you will see a validation error and can shorten the name.', 'Is there a character limit for the Ad Group Name?

We follow Google''s limits behind the scenes. Practically speaking:
Keep Ad Group Names short and scannable, ideally under 80 characters.
Use plain text without emojis or special characters, which can make reporting harder to read.
If you hit a limit, you will see a validation error and can shorten the name.', 'Ad Group Name', '{}', 1, NULL, '2025-11-29 17:39:13.807746', '2025-11-29 17:39:13.807746');
INSERT INTO public.document_chunks VALUES (73, 5, '34847d330671079a7d1a7056f0e5676f8e7fd3382b3984fdd88093e35be9df6f', 'What are Headlines in my ad?', 'Headlines are short text snippets (up to 30 characters each) that appear as the bold, clickable part of your Google Search ad.
In a live ad, Google usually shows 2–3 headlines at a time, side by side. With Responsive Search Ads, Google can test different combinations of the headlines you provide.
On this page, you can:
Enter your own headlines
Edit AI-generated suggestions
Add extra headline options for Google to test', 'What are Headlines in my ad?

Headlines are short text snippets (up to 30 characters each) that appear as the bold, clickable part of your Google Search ad.
In a live ad, Google usually shows 2–3 headlines at a time, side by side. With Responsive Search Ads, Google can test different combinations of the headlines you provide.
On this page, you can:
Enter your own headlines
Edit AI-generated suggestions
Add extra headline options for Google to test', 'Headlines', '{}', 2, NULL, '2025-11-29 17:39:13.821228', '2025-11-29 17:39:13.821228');
INSERT INTO public.document_chunks VALUES (74, 5, '4fd1f80d369ef886ef0e96b9619b058b93c3ab07e5519948e3d7fbc7c8c338ba', 'Why do I see "Select 3–15" for Headlines?', 'Google requires that a Responsive Search Ad has:
At least 3 active headlines
Up to 15 total headlines
Launch10 lets you:
Add many headline ideas.
Choose which ones count as active (up to 15). Make sure to click the lock for headlines you''d like to keep
Your campaign cannot be launched until at least 3 headlines are selected.', 'Why do I see "Select 3–15" for Headlines?

Google requires that a Responsive Search Ad has:
At least 3 active headlines
Up to 15 total headlines
Launch10 lets you:
Add many headline ideas.
Choose which ones count as active (up to 15). Make sure to click the lock for headlines you''d like to keep
Your campaign cannot be launched until at least 3 headlines are selected.', 'Headlines', '{}', 3, NULL, '2025-11-29 17:39:13.834234', '2025-11-29 17:39:13.834234');
INSERT INTO public.document_chunks VALUES (84, 5, '4c9603ae03f69db2897f51de336d10325b009f22c417c67b67ffb7c70f5f168b', 'Will changing my content later affect my campaign?', 'Yes. When you edit Headlines or Details after launch:
We will sync the changes to Google Ads.
Google may need some time to re-learn which combinations perform best.
Your previous performance data stays in Google, but the "learning" phase may restart for new content.
Small, focused changes are usually better than rewriting everything at once unless you are repositioning your offer.', 'Will changing my content later affect my campaign?

Yes. When you edit Headlines or Details after launch:
We will sync the changes to Google Ads.
Google may need some time to re-learn which combinations perform best.
