INSERT INTO public.document_chunks VALUES (78, 5, 'a4183b4fa407820fc10e6dbd77cc6bb060cf61da1deb2ed4a087c16eac037e6c', 'Will Launch10 check if my headlines comply with Google Ads policies?', 'We do our best to keep suggestions within common Google Ads guidelines, but:
Google makes the final decision about ad approval.
If Google flags or disapproves a headline, you may need to adjust wording (for example, remove prohibited claims, sensitive content, or certain trademarks).
If a headline is rejected, you can:
Edit it manually, or
Use "Refresh Suggestions" and pick an alternative.', 'Will Launch10 check if my headlines comply with Google Ads policies?

