INSERT INTO public.document_chunks VALUES (96, 5, '8d25ef4e5b2e9faccc13e436b1dce12e2655f488fc821fb07198c6f508496011', 'What happens if I leave Unique Features blank?', 'In many cases your ad can still run with just headlines and descriptions, but:
You will miss an opportunity to take up more space in search results.
Your ad may feel less compelling compared to competitors using callouts.
We encourage you to add at least 2 Unique Features because they are a quick way to improve performance.', 'What happens if I leave Unique Features blank?

