INSERT INTO public.document_chunks VALUES (86, 5, '273a9d120fd14aee47837640419503ea3bef82c0c1c182c1c12703cd7aeccdcc', 'How does this Content page relate to the "Highlights" tab?', 'On the Content tab you write the main ad text that appears in almost every impression.
On the Highlights tab (next step):
You will usually add structured information such as features, service types, or callouts, depending on the configuration.
These often map to Google ad extensions (now called "assets"), which can show in addition to your headlines and descriptions.
You should complete the Content tab first, since this is the foundation of your ad.', 'How does this Content page relate to the "Highlights" tab?

On the Content tab you write the main ad text that appears in almost every impression.
On the Highlights tab (next step):
You will usually add structured information such as features, service types, or callouts, depending on the configuration.
These often map to Google ad extensions (now called "assets"), which can show in addition to your headlines and descriptions.
