INSERT INTO public.document_chunks VALUES (99, 5, 'c9396302608927dfa8ee3b182d30b56766c1a10ef55fc4b8f50111fde6a011de', 'How do I choose the right Category?', 'Pick the category that best describes how your list items fit together.
For "pet photography" examples:
Services – if your list items are types of services (studio sessions, outdoor sessions).
Types – if your items are portrait types (solo pets, pets with families, holiday sessions).
Styles – if items are artistic styles (classic, lifestyle, candid, black-and-white).
If more than one category seems right, choose the one that would be clearest to a new customer who has never heard of you.', 'How do I choose the right Category?

Pick the category that best describes how your list items fit together.
For "pet photography" examples:
Services – if your list items are types of services (studio sessions, outdoor sessions).
Types – if your items are portrait types (solo pets, pets with families, holiday sessions).
Styles – if items are artistic styles (classic, lifestyle, candid, black-and-white).
